// TestTry_HappyPath_ClaimsAndExecutes verifies the core AC: given a ready bead
// and a stub executor that returns success, the command claims the bead,
// invokes the executor, and exits zero.
func TestTry_HappyPath_ClaimsAndExecutes(t *testing.T) {
	env := NewTestEnvironment(t)
	store := bead.NewStore(env.Dir + "/.ddx")
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "happy-bead-001",
		Title: "Happy path bead",
	}))

	var executorCalled bool
	stubExecutor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		executorCalled = true
		assert.Equal(t, "happy-bead-001", beadID, "executor must receive the targeted bead ID")
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			ResultRev: "deadbeef01234567", // non-empty so ClosureGate passes
		}, nil
	})

	factory := NewCommandFactory(env.Dir)
	factory.tryExecutorOverride = stubExecutor
	root := factory.NewRootCommand()

	out, err := executeCommand(root, "try", "happy-bead-001", "--no-review", "--no-review-i-know-what-im-doing")
	require.NoError(t, err, "ddx try with a successful stub executor must exit zero: %s", out)
	assert.True(t, executorCalled, "executor must have been called")

	// Verify the bead was claimed (status should be closed after success).
	b, storeErr := store.Get("happy-bead-001")
	require.NoError(t, storeErr)
	assert.Equal(t, bead.StatusClosed, b.Status, "bead must be closed after successful execution")
}

// TestTry_FlagsPlumbThrough verifies that routing flags (--harness, --model)
// reach the executor. We capture the resolved config in the stub executor.
func TestTry_FlagsPlumbThrough(t *testing.T) {
	env := NewTestEnvironment(t)
	store := bead.NewStore(env.Dir + "/.ddx")
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "flag-bead-001",
		Title: "Flag plumbing bead",
	}))

	var capturedBeadID string
	stubExecutor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		capturedBeadID = beadID
		return agent.ExecuteBeadReport{
			BeadID: beadID,
			Status: agent.ExecuteBeadStatusSuccess,
		}, nil
	})

	factory := NewCommandFactory(env.Dir)
	factory.tryExecutorOverride = stubExecutor
	root := factory.NewRootCommand()

	// The --harness and --model flags are passthrough — they reach the runtime
	// config (CLIOverrides). Since the stub executor bypasses the real agent,
	// we assert the flags are accepted without error (no flag-parsing failure)
	// and the executor is invoked with the correct bead ID.
	out, err := executeCommand(root, "try", "flag-bead-001",
		"--harness=codex", "--model=gpt-5.4-mini", "--no-review", "--no-review-i-know-what-im-doing")
	require.NoError(t, err, "ddx try with routing flags must not fail on flag parsing: %s", out)
	assert.Equal(t, "flag-bead-001", capturedBeadID,
		"executor must receive the correct bead ID regardless of routing flags")
	// Verify the flags appear in help (AC #7 surface check).
	tryCmd, _, findErr := root.Find([]string{"try"})
	require.NoError(t, findErr)
	assert.NotNil(t, tryCmd.Flags().Lookup("harness"), "try must expose --harness flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("model"), "try must expose --model flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("profile"), "try must expose --profile flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("provider"), "try must expose --provider flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("no-review"), "try must expose --no-review flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("no-review-i-know-what-im-doing"), "try must expose the break-glass acknowledgement flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("review-harness"), "try must expose --review-harness flag")
	assert.NotNil(t, tryCmd.Flags().Lookup("review-model"), "try must expose --review-model flag")
}

// TestTry_HooksWired verifies that ddx try wires the pre-dispatch lint and
// post-attempt triage hooks into ExecuteBeadLoopRuntime, and that both hooks
// route through the shared runner override seam.
func TestTry_HooksWired(t *testing.T) {
	env := NewTestEnvironment(t)
	skillPath := env.Dir + "/.agents/skills/ddx/bead-lifecycle"
	require.NoError(t, os.MkdirAll(skillPath, 0o755))
	require.NoError(t, os.WriteFile(skillPath+"/SKILL.md", []byte("lint + triage"), 0o644))
	store := bead.NewStore(env.Dir + "/.ddx")
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "hook-bead-001",
		Title: "Hook wiring bead",
	}))

	runner := &tryHookRunnerStub{t: t}
	factory := NewCommandFactory(env.Dir)
	factory.AgentRunnerOverride = runner
	factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusNoChanges,
			Detail:    "nothing changed",
			BaseRev:   "feedface",
			ResultRev: "feedface",
			SessionID: "sess-hook",
		}, nil
	})

	out, err := executeCommand(
		factory.NewRootCommand(),
		"try",
		"hook-bead-001",
		"--harness=codex",
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)
	require.Error(t, err)
	assert.Contains(t, out, "bead:", "try command should still render the terminal report")
	assert.Equal(t, []string{"bead-lifecycle-lint", "bead-lifecycle-triage"}, runner.promptSource)

	events, err := store.Events("hook-bead-001")
	require.NoError(t, err)
	var lintSeen, triageSeen bool
	for _, ev := range events {
		switch ev.Kind {
		case "bead-quality.lint":
			lintSeen = true
		case "bead-quality.triage":
			triageSeen = true
		}
	}
	assert.True(t, lintSeen, "try must emit the lint event when the hook is wired")
	assert.True(t, triageSeen, "try must emit the triage event when the hook is wired")

	profile = agent.NormalizeRoutingProfile(profile)

	// SD-024 Stage 1: dispatch flows through LoadAndResolve + RunWithConfig
	// so .ddx/config.yaml's durable knobs (review_max_retries,
	// no_progress_cooldown, max_no_changes_before_close, heartbeat_interval,
	// agent.harness/model/permissions, etc.) reach the running loop without
	// per-knob CLI plumbing. CLI flag values feed CLIOverrides which win
	// over the on-disk config when set.
	overrides := config.CLIOverrides{
		Assignee:          resolveClaimAssignee(),
		Harness:           harness,
		Model:             model,
		Provider:          provider,
		ModelRef:          modelRef,
		Profile:           profile,
		Effort:            effort,
		MinPower:          minPower,
		OpaquePassthrough: treatPassthroughAsOpaque,
	}
	rcfg, err := config.LoadAndResolve(projectRoot, overrides)
	if err != nil {
		// Surface the LoadAndResolve error rather than letting a
		// zero-value ResolvedConfig flow into RunWithConfig — the
		// SD-024 sealed-construction sentinel would otherwise panic
		// at first accessor read instead of producing a clean CLI error.
		return fmt.Errorf("load resolved config: %w", err)
	}

	var qualityRunner agent.AgentRunner
	if f.AgentRunnerOverride != nil {
		qualityRunner = f.AgentRunnerOverride
	}
	lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
	intakeHook := agent.NewPreClaimIntakeHook(projectRoot, store, rcfg, nil, qualityRunner)
	triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)

	// Cost-cap state shared across attempts for this loop run.
	// paths. Accumulated billed spend (excluding local and subscription
	// providers) above --max-cost trips the cap and halts further bead
	// claiming. See escalation.DefaultMaxCostUSD / CountsTowardCostCap.
	costCap := escalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
		// Resolve the harness's billing class via the service. Treat any
		// resolution error as "count by default" (safe — we'd rather cap
		// early than silently overshoot).
		svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
		if svcErr != nil {
			return true
		}
		infos, err := svc.ListHarnesses(context.Background())
		if err != nil {
			return true
		}
		for _, h := range infos {
			if h.Name == harnessName {
				return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
			}
		}
		return true
	})
	accumulateBilledCost := func(report agent.ExecuteBeadReport) {
		costCap.Add(report.Harness, report.CostUSD)
	}
	costCapTripped := func() (agent.ExecuteBeadReport, bool) {
		if _, tripped := costCap.Tripped(); !tripped {
			return agent.ExecuteBeadReport{}, false
		}
		spent := costCap.Spent()
		return agent.ExecuteBeadReport{
			Status: agent.ExecuteBeadStatusExecutionFailed,
			Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, maxCostUSD),
		}, true
	}

	// singleTierAttempt runs one execution attempt with an explicit harness
	// and model. The caller controls MinPower per rung; this helper keeps the
	// profile stable and only advances the power floor.
	singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
		gitOps := &agent.RealGitOps{}
		attemptProvider := provider
		if resolvedProvider != "" {
			attemptProvider = resolvedProvider
		}
		loopOverrides := config.CLIOverrides{
			Harness:           resolvedHarness,
			Model:             resolvedModel,
			Provider:          attemptProvider,
			ModelRef:          modelRef,
			Profile:           profile,
			Effort:            effort,
			MinPower:          requestedMinPower,
			MaxPower:          maxPower,
			OpaquePassthrough: treatPassthroughAsOpaque,
		}
		if requestTimeout > 0 {
			loopOverrides.ProviderRequestTimeout = &requestTimeout
		}
		attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
		res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
			FromRev:     fromRev,
			BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
			AgentRunner: f.AgentRunnerOverride,
		}, gitOps)
		if execErr != nil && res == nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
			targetBead, _ := store.Get(beadID)
			landRes, _, landErr := agent.SubmitWithPreMergeChecks(
				ctx, projectRoot, targetBead, res,
				func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
				resolveClaimAssignee(), "ddx agent execute-loop",
				nil,
			)
			if landErr == nil {
				agent.ApplyLandResultToExecuteBeadResult(res, landRes)
			} else if execErr == nil {
				execErr = landErr
			}
		} else if res != nil && res.ResultRev == res.BaseRev {
			res.Outcome = "no-changes"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		} else if res != nil && res.ExitCode != 0 {
			res.Outcome = "preserved"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		}
		if execErr != nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		return agent.ExecuteBeadReport{
			BeadID:                      res.BeadID,
			AttemptID:                   res.AttemptID,
			WorkerID:                    res.WorkerID,
			Harness:                     res.Harness,
			Provider:                    res.Provider,
			Model:                       res.Model,
			ActualPower:                 res.ActualPower,
			PredictedPower:              res.PredictedPower,
			PredictedSpeedTPS:           res.PredictedSpeedTPS,
			PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
			PredictedCostSource:         res.PredictedCostSource,
			Status:                      res.Status,
			Detail:                      res.Detail,
			SessionID:                   res.SessionID,
			BaseRev:                     res.BaseRev,
			ResultRev:                   res.ResultRev,
			PreserveRef:                 res.PreserveRef,
			NoChangesRationale:          res.NoChangesRationale,
			CostUSD:                     res.CostUSD,
			DurationMS:                  int64(res.DurationMS),
		}, nil
	}

	var ladderOnce sync.Once
	var ladder escalationFloorFinder
	loadLadder := func() escalationFloorFinder {
		ladderOnce.Do(func() {
			ladder = tierescalation.NewLadder(nil)
			svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
			if svcErr != nil {
				return
			}
			modelFilter := agentlib.ModelFilter{}
			if harness != "" {
				modelFilter.Harness = harness
			}
			modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
			defer cancel()
			models, listErr := svc.ListModels(modelCtx, modelFilter)
			if listErr != nil {
				return
			}
			ladder = tierescalation.NewLadder(models)
		})
		return ladder
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    store,
		Reviewer: reviewer,
		Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			// Stop AT THE START of each new bead claim if the cost cap has
			// already tripped — otherwise we'd burn one extra attempt before
			// halting the queue.
			if cappedReport, capped := costCapTripped(); capped {
				cappedReport.BeadID = beadID
				return cappedReport, nil
			}
			report, err := runEscalatingSingleTierAttempts(
				ctx,
				rcfg.MinPower(),
				loadLadder(),
				func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
					return singleTierAttempt(ctx, beadID, requestedMinPower, harness, provider, model)
				},
				nil,
			)
			if err == nil {
				accumulateBilledCost(report)
				if cappedReport, capped := costCapTripped(); capped {
					cappedReport.BeadID = beadID
					return cappedReport, nil
				}
			}
			return report, err
		}),
	}

	cliLandingOps := agent.RealLandingGitOps{}
	result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
		Once:                  once,
		PollInterval:          pollInterval,
		Log:                   cmd.OutOrStdout(),
		EventSink:             loopSink,
		WorkerID:              resolveClaimAssignee(),
		ProjectRoot:           projectRoot,
		SessionID:             loopSessionID,
		PreClaimHook:          buildCLIPreClaimHook(projectRoot, cliLandingOps),
		PreClaimIntakeHook:    intakeHook,
		PreDispatchLintHook:   lintHook,
		PostAttemptTriageHook: triageHook,
		NoReview:              noReview,
		TargetBeadID:          tryTargetBeadID,
		ReviewCostCap:         costCap,
	})
	if err != nil {
		return err
	}
	return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, asJSON)
}

